SELECT id, title, summary, content, cover, category_id AS categoryId, status, view_count AS viewCount, create_time AS createTime, update_time AS updateTime FROM article WHERE status = 1
AND id != #{excludeId}
AND (
(title LIKE CONCAT('%', #{kw}, '%') OR summary LIKE CONCAT('%', #{kw}, '%') OR content LIKE CONCAT('%', #{kw}, '%'))
)
ORDER BY create_time DESC LIMIT #{limit}

